settings.polygonColorFunction:
function (entity) {
  const state = (entity.data.attributes || {}).state;
  
  if (state === 'Not Analyzed') {
    return 'red';
  } else if (state === 'Analyzed') {
    return 'yellow';
  } else if (state === 'Sprayed') {
    return 'green';
  } else {
    return 'gray'; // Default color for unknown states
  }
}

