settings.polygonColorFunction:
return (data && Number.isFinite(data.amount)) ? (function() {
    const amount = data.amount;
    if (amount === 0) {
        return 'rgba(0, 128, 0, 1)'; // Green
    } else if (amount < 2) {
        return 'rgba(173, 255, 47, 1)'; // Light green
    } else if (amount < 4) {
        return 'rgba(255, 255, 0, 1)'; // Yellow
    } else if (amount < 6) {
        return 'rgba(255, 165, 0, 1)'; // Orange
    } else if (amount < 8) {
        return 'rgba(255, 0, 0, 1)'; // Red
    } else if (amount < 10) {
        return 'rgba(128, 0, 128, 1)'; // Purple
    } else if (amount >= 10) {
        return 'rgba(0, 0, 0, 1)'; // Black
    } else {
        return 'rgba(0, 0, 255, 0)'; // Default: transparent
    }
})() : 'rgba(0, 0, 255, 0)'; // No data: transparent

