settings.dashboardCss:
/* --- Global Widget Container Styling --- */
.tb-widget-container {
    background: rgba(20, 20, 25, 0.85) !important; /* Deep dark background with transparency */
    backdrop-filter: blur(8px); /* Modern frosted glass effect */
    border: 1px solid rgba(0, 243, 255, 0.1) !important; /* Subtle neon-blue border */
    border-radius: 12px !important;
    box-shadow: 0 8px 32px 0 rgba(0, 0, 0, 0.8) !important;
    transition: all 0.4s cubic-bezier(0.25, 0.8, 0.25, 1) !important;
    overflow: hidden;
}

/* --- Hover Effect: Neon Blue Glow --- */
.tb-widget-container:hover {
    border-color: #00f3ff !important; /* Bright neon blue border */
    box-shadow: 0 0 20px rgba(0, 243, 255, 0.4), 
                inset 0 0 10px rgba(0, 243, 255, 0.1) !important;
    transform: translateY(-4px); /* Subtle lift effect */
}

/* --- Widget Titles Styling --- */
.tb-widget-title {
    color: #00f3ff !important; /* Cyan neon text */
    font-weight: 600 !important;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    font-size: 0.9rem !important;
    text-shadow: 0 0 8px rgba(0, 243, 255, 0.5);
}

/* --- Table & List Customization --- */
/* This ensures your fleet lists and mission tables match the theme */
.mat-table {
    background: transparent !important;
}

.mat-header-cell {
    color: #00f3ff !important;
    border-bottom: 2px solid rgba(0, 243, 255, 0.2) !important;
    text-transform: uppercase;
    font-size: 0.75rem;
}

.mat-cell {
    color: #e0e0e0 !important;
    border-bottom: 1px solid rgba(255, 255, 255, 0.05) !important;
}

.mat-row:hover {
    background: rgba(0, 243, 255, 0.05) !important;
}

/* --- Custom Tech Scrollbar --- */
::-webkit-scrollbar {
    width: 6px;
    height: 6px;
}

::-webkit-scrollbar-track {
    background: rgba(0, 0, 0, 0.2);
}

::-webkit-scrollbar-thumb {
    background: #00f3ff;
    border-radius: 10px;
    box-shadow: 0 0 5px #00f3ff;
}

/* --- Map & Action Buttons --- */
/* Makes buttons look like digital interfaces */
.mat-button, .mat-raised-button {
    border-radius: 4px !important;
    text-transform: uppercase;
    letter-spacing: 1px;
}

/* Esto fuerza el fondo en todo el layout del dashboard */
.tb-dashboard-page .tb-dashboard-content {
    background-image: url('https://static.vecteezy.com/system/resources/previews/001/882/531/non_2x/dark-blue-technology-background-free-vector.jpg') !important; /* Puedes cambiar este link por tu imagen */
    background-size: cover !important;
    background-attachment: fixed !important;
    background-position: center !important;
    background-color: #050505 !important; /* Color de respaldo */
}

/* Oscurecer un poco el fondo para que los widgets resalten más */
.tb-dashboard-page .tb-dashboard-content::before {
    content: "";
    position: absolute;
    top: 0; left: 0; width: 100%; height: 100%;
    background: rgba(0, 0, 0, 0.4); /* Capa de oscuridad extra */
    z-index: 0;
}

.tb-widget-container {
    border: 1px solid rgba(0, 243, 255, 0.3) !important;
    border-radius: 8px !important;
    backdrop-filter: blur(5px); /* Esto hará que se vea profesional sobre el fondo azul */
}
